  ('disabled-57f41407-moex-00446', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '關於刑法第140條侮辱公務員或公署罪之規定，下列何者正確？', '["對公署侮辱不以公然為必要", "侮辱內容須與公務有關", "公署是指建築物", "公然係指眾人得共聞共見"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00447', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '甲散步公園中，突然迎面而來乙所飼養之狼犬欲對甲攻擊，甲情急之下持 木棍對該狼犬頭部猛力敲打1下，致狼犬死亡，甲應否負刑事責任？', '["可依緊急避難規定，阻卻違法", "屬正當防衛過當，至多只能減輕其刑", "可依正當防衛規定，阻卻違法", "因狼犬為乙所飼養，構成毀損罪，但得減輕其刑"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00448', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '貪污治罪條例第8條所定自首或自白減免其刑之規定，關於「因而查獲其 他正犯或共犯」，依實務見解，下列何者正確？', '["被告具體指認其他正犯或共犯，即得依上開規定減免其刑", "被告具體指認其他正犯或共犯，並詳實供出渠等參與貪污犯罪情節之具 體事證，即得依上開規定減免其刑", "被告具體指認其他正犯或共犯，並詳實供出渠等參與貪污犯罪情節之具 體事證，使偵查或調查犯罪職權之公務員知悉，而發動偵查或調查，即 得依上開規定減免其刑", "被告具體指認其他正犯或共犯，並詳實供出渠等參與貪污犯罪情節之具 體事證，使偵查或調查犯罪職權之公務員知悉，而發動偵查或調查，因 此查獲其他正犯或共犯，始得依上開規定減免其刑"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00449', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '16歲甲之父母尚未留下遺囑即意外雙亡，與21歲之姊姊乙、17歲之姊姊 丁同住相依為命。另有82歲之爺爺戊與75歲之外婆庚住在附近，可隨時 照應。依民法規定，誰優先有對甲之監護權？', '["庚", "戊", "丁", "乙"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00450', 'disabled-57f41407', 'disabled-57f41407-moex-112-55d283b0', 'sub-disabled-57f41407-03', NULL, 'single_choice', '依實務見解，關於刑法第20條瘖啞人之行為，得減輕其刑，下列何者正確？', '["行為人行為時瘖或啞即可", "行為人須出生或年幼瘖啞", "行為人瘖而不啞亦可適用", "行為人啞而不瘖亦可適用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "d2b7cdb0e0cd", "answer_pdf_sha1": "8efc4435d7d1", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0310", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00451', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '審計部抽查各大學校院支給專、兼任助理酬金情況，發現未盡妥適，因此 發文告知教育部，教育部則轉知各校留意改善。審計部發給教育部的公文， 以及教育部發給各校的公文，依序應為：', '["簽／令", "呈／函", "函／函", "函／簽"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00452', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '下列公文用語，何者說明錯誤？', '["此致、此上：於簽末使用", "附送：對平行及下級機關用", "請查照見復：對平行機關用", "應予照准：上級機關對下級機關或首長用"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00453', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '下級稱呼無隸屬關係的上級，應使用下列何種稱謂用語？', '["鈞", "大", "貴", "本"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00454', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '下列有關「簽」的敘述，正確的是：', '["一般存參或案情簡單之文件，得於原件文中空白處簽擬", "「簽」的結構採用「主旨」、「說明」、「辦法」3段式書寫", "承辦人員對長官有所陳述、請示、請求、建議時使用，及長官諭令屬下 皆屬之", "機關內部單位簽辦案件：雖依分層授權規定核決，但簽末仍須敘明陳某 某長官字樣"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00455', 'disabled-57f41407', 'disabled-57f41407-moex-111-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '李大偉奉派出國受訓，寫信向祖父請安，信中用詞不當的選項是：', '["起始稱謂為「祖父大人」", "提稱語為「膝前」", "信末問候語為「順請 福安」", "結尾署名敬辭為「孫 大偉叩稟」"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:37+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "506", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
